async (params, browser) => {
  // Open Figma file
  await browser.open(`${params.file_url}`)

  // Wait for editor to load
  await browser.waitForSelector('[class*="toolbar"], [data-testid="canvas"]', 20000)

  // Let canvas and panels render
  await browser.wait(4000)

  // Open assets panel
  await browser.click('[class*="assets_panel"] [class*="tab"], [data-testid="assets-tab"], button[aria-label*="Assets"], [class*="left_panel"] [class*="assets"], [class*="panel_tab"][class*="asset"]')

  // Let assets panel load
  await browser.wait(2000)

  // Extract components from assets panel
  const result = await browser.evaluate(`const components = []; const items = document.querySelectorAll('[class*="assets_panel"] [class*="component"], .assets-panel [class*="item"], [class*="asset_row"], [class*="component_item"], [data-testid="asset-item"]'); items.forEach((item, i) => { if (i >= 50) return; const nameEl = item.querySelector('[class*="name"], [class*="label"], [class*="title"]'); const descEl = item.querySelector('[class*="description"], [class*="desc"]'); const thumbEl = item.querySelector('img, [class*="thumbnail"], [class*="preview"]'); components.push({ name: nameEl ? nameEl.textContent.trim() : item.textContent.trim().substring(0, 100), description: descEl ? descEl.textContent.trim() : '', has_thumbnail: !!thumbEl }); }); const groups = []; const groupHeaders = document.querySelectorAll('[class*="assets_panel"] [class*="group_header"], [class*="assets_panel"] [class*="section_header"], [class*="component_group"]'); groupHeaders.forEach(g => { groups.push(g.textContent.trim()); }); return { file_url: window.location.href, component_count: components.length, component_groups: groups, components: components }`)

  return result
}
